<script setup>
import ArticleHeader from '@/components/ArticleHeader.vue'
import ArticleBody from '@/components/ArticleBody.vue'

const post = {
  id: "springboot-docker",
  title: "Spring Boot 애플리케이션 Docker 컨테이너화",
  date: "2026-02-11",
  summary: "Spring Boot 3.x와 Java 21 기반 Docker 이미지 빌드, 멀티 스테이지 빌드, Jib, 최적화 팁까지 정리합니다.",
  category: "Technology/SpringBoot",
  tags: ["springboot","docker","container","devops","kubernetes"],
  content: ["## Spring Boot를 Docker로 배포하기", "Spring Boot 애플리케이션을 Docker 이미지로 패키징하고 컨테이너에서 실행하는 방법을 정리합니다. Java 17/21 + Slim 베이스 이미지로 용량과 보안을 최적화할 수 있습니다.", "", "이 글에서는 먼저 **IntelliJ에서 프로젝트를 생성하고 코드를 작성한 뒤 Docker로 컨테이너화**하는 전 과정을 실습합니다. 이후 Jib, GraalVM Native Image 등 고급 주제를 다룹니다.", "", "---", "", "## 실습: 프로젝트 처음부터 Docker 실행까지", "", "### 1. 인텔리제이 프로젝트 만들기", "IntelliJ IDEA에서 **New Project**를 선택하고 다음과 같이 설정합니다.", "", "| 항목 | 값 |", "| --- | --- |", "| **Name** | `springboot_docker_example` |", "| **Language** | Java |", "| **Build System** | Gradle - Groovy |", "| **JDK** | 21 |", "| **Spring Boot** | 3.x (최신 안정 버전) |", "| **Dependencies** | Lombok, Spring Web |", "", "### 2. build.gradle 설정", "프로젝트가 생성되면 `build.gradle` 파일을 아래와 같이 확인/수정합니다.", "", "```groovy", "plugins {", "    id 'java'", "    id 'org.springframework.boot' version '3.4.3'", "    id 'io.spring.dependency-management' version '1.1.7'", "}", "", "group = 'com.example'", "version = '0.0.1-SNAPSHOT'", "", "java {", "    toolchain {", "        languageVersion = JavaLanguageVersion.of(21)", "    }", "}", "", "repositories {", "    mavenCentral()", "}", "", "dependencies {", "    implementation 'org.springframework.boot:spring-boot-starter-web'", "    compileOnly 'org.projectlombok:lombok'", "    annotationProcessor 'org.projectlombok:lombok'", "    testImplementation 'org.springframework.boot:spring-boot-starter-test'", "}", "", "tasks.named('test') {", "    useJUnitPlatform()", "}", "```", "", "### 3. 소스 코드 작성", "#### DemoApplication.java", "`src/main/java/com/example/demo/DemoApplication.java`", "", "```java", "package com.example.demo;", "", "import org.springframework.boot.SpringApplication;", "import org.springframework.boot.autoconfigure.SpringBootApplication;", "", "@SpringBootApplication", "public class DemoApplication {", "    public static void main(String[] args) {", "        SpringApplication.run(DemoApplication.class, args);", "    }", "}", "```", "", "#### HelloController.java", "`src/main/java/com/example/demo/HelloController.java`", "", "```java", "package com.example.demo;", "", "import lombok.extern.slf4j.Slf4j;", "import org.springframework.web.bind.annotation.GetMapping;", "import org.springframework.web.bind.annotation.RestController;", "", "import java.net.InetAddress;", "import java.time.LocalDateTime;", "import java.util.Map;", "", "@Slf4j", "@RestController", "public class HelloController {", "", "    @GetMapping(\"/api/hello\")", "    public Map<String, String> hello() {", "        String hostname = \"unknown\";", "        try {", "            hostname = InetAddress.getLocalHost().getHostName();", "        } catch (Exception e) {", "            log.warn(\"hostname 조회 실패\", e);", "        }", "        return Map.of(", "            \"message\", \"Hello from Spring Boot in Docker!\",", "            \"hostname\", hostname,", "            \"timestamp\", LocalDateTime.now().toString()", "        );", "    }", "}", "```", "", "#### application.yml", "`src/main/resources/application.yml`", "", "```yaml", "server:", "  port: 8080", "", "spring:", "  application:", "    name: springboot-docker-example", "```", "", "### 4. Dockerfile 작성 (멀티 스테이지 빌드)", "프로젝트 루트에 `Dockerfile`을 생성합니다.", "", "```dockerfile", "FROM eclipse-temurin:21-jdk AS build", "WORKDIR /app", "COPY . .", "RUN ./gradlew bootJar", "", "FROM eclipse-temurin:21-jre", "WORKDIR /app", "COPY --from=build /app/build/libs/*.jar app.jar", "EXPOSE 8080", "ENTRYPOINT [\"java\", \"-jar\", \"app.jar\"]", "```", "", "> 첫 번째 스테이지에서 Gradle로 빌드하고, 두 번째 스테이지에서는 JRE만 포함한 경량 이미지에 JAR를 복사합니다.", "", "### 5. docker-compose.yml 작성", "프로젝트 루트에 `docker-compose.yml`을 생성합니다.", "", "```yaml", "version: '3.8'", "services:", "  app:", "    build: .", "    ports:", "      - \"8080:8080\"", "    environment:", "      - SPRING_PROFILES_ACTIVE=prod", "```", "", "### 6. .dockerignore 작성", "불필요한 파일이 Docker 빌드 컨텍스트에 포함되지 않도록 `.dockerignore`를 작성합니다.", "", "```text", ".git", ".gradle", "build", "!build/libs", ".idea", "*.iml", "```", "", "### 7. 빌드 및 실행", "```bash", "# Docker 이미지 빌드", "docker build -t myapp .", "", "# 컨테이너 실행", "docker run -p 8080:8080 myapp", "", "# 또는 docker-compose로 실행", "docker-compose up", "```", "", "실행 후 `http://localhost:8080/api/hello`에 접속하면 hostname과 timestamp가 포함된 JSON 응답을 확인할 수 있습니다.", "", "```json", "{", "  \"message\": \"Hello from Spring Boot in Docker!\",", "  \"hostname\": \"a1b2c3d4e5f6\",", "  \"timestamp\": \"2026-02-11T14:30:00.123456\"", "}", "```", "", "---", "", "## 1) 기본 Dockerfile (멀티 스테이지)", "```dockerfile", "FROM eclipse-temurin:21-jdk-alpine AS builder", "WORKDIR /app", "", "COPY mvnw .", "COPY .mvn .mvn", "COPY pom.xml .", "RUN ./mvnw dependency:go-offline -B", "", "COPY src ./src", "RUN ./mvnw package -DskipTests -B", "", "FROM eclipse-temurin:21-jre-alpine", "WORKDIR /app", "", "RUN addgroup -g 1001 -S appgroup && adduser -u 1001 -S appuser -G appgroup", "COPY --from=builder /app/target/*.jar app.jar", "", "USER appuser", "EXPOSE 8080", "ENTRYPOINT [\"java\", \"-jar\", \"app.jar\"]", "```", "", "## 2) Gradle Dockerfile", "```dockerfile", "FROM eclipse-temurin:21-jdk-alpine AS builder", "WORKDIR /app", "COPY . .", "RUN ./gradlew bootJar -x test --no-daemon", "", "FROM eclipse-temurin:21-jre-alpine", "WORKDIR /app", "COPY --from=builder /app/build/libs/*.jar app.jar", "EXPOSE 8080", "ENTRYPOINT [\"java\", \"-jar\", \"app.jar\"]", "```", "", "## 3) Jib으로 Dockerfile 없이 빌드", "Google Jib을 사용하면 Dockerfile 없이 Gradle/Maven만으로 이미지를 빌드합니다.", "", "```xml", "<!-- Maven -->", "<plugin>", "    <groupId>com.google.cloud.tools</groupId>", "    <artifactId>jib-maven-plugin</artifactId>", "    <version>3.4.0</version>", "    <configuration>", "        <from>", "            <image>eclipse-temurin:21-jre-alpine</image>", "        </from>", "        <to>", "            <image>myregistry/my-app:latest</image>", "        </to>", "        <container>", "            <ports><port>8080</port></ports>", "            <user>1001:1001</user>", "        </container>", "    </configuration>", "</plugin>", "```", "", "```bash", "# 빌드 및 푸시", "mvn compile jib:build", "# 로컬 Docker만", "mvn compile jib:dockerBuild", "```", "", "## 4) Spring Boot 3.x 네이티브 이미지 (GraalVM)", "GraalVM Native Image로 초기 구동 시간을 크게 줄일 수 있습니다.", "", "```xml", "<plugin>", "    <groupId>org.graalvm.buildtools</groupId>", "    <artifactId>native-maven-plugin</artifactId>", "</plugin>", "```", "", "```bash", "./mvnw -Pnative native:compile", "```", "", "생성된 네이티브 실행 파일을 Alpine에 넣으면 수 MB 수준의 초경량 이미지가 됩니다.", "", "## 5) docker-compose 예제", "```yaml", "version: '3.8'", "services:", "  app:", "    build: .", "    ports:", "      - \"8080:8080\"", "    environment:", "      SPRING_DATASOURCE_URL: jdbc:postgresql://db:5432/mydb", "      SPRING_DATASOURCE_USERNAME: user", "      SPRING_DATASOURCE_PASSWORD: pass", "    depends_on:", "      - db", "  db:", "    image: postgres:16-alpine", "    environment:", "      POSTGRES_DB: mydb", "      POSTGRES_USER: user", "      POSTGRES_PASSWORD: pass", "    volumes:", "      - dbdata:/var/lib/postgresql/data", "volumes:", "  dbdata:", "```", "", "## 6) 최적화 팁", "- JRE 베이스 이미지 사용 (JDK 불필요 시)", "- distroless 또는 alpine으로 이미지 크기 축소", "- 레이어 캐싱: 의존성 복사 → 소스 복사 순으로 Dockerfile 작성", "- `java -jar` 시 `-XX:+UseContainerSupport` 등 JVM 옵션으로 컨테이너 메모리 인식", "", "## 정리", "Spring Boot + Docker는 실무 표준 조합입니다. Jib이나 Buildpacks로 Dockerfile 없이 빌드할 수도 있고, GraalVM Native로 더 빠른 구동이 필요하면 네이티브 이미지를 고려하면 됩니다."]
}
</script>

<template>
  <ArticleHeader :post="post" />
  <ArticleBody :content="post.content" />
</template>
